import React, { useState, useEffect } from 'react';
import { trackCTAClick, trackNavClick, trackPhoneClick } from '../services/tracking';

const Header: React.FC = () => {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isScrolled, setIsScrolled] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const toggleMenu = () => {
        setIsMenuOpen(!isMenuOpen);
    };

    const handleScrollClick = (event: React.MouseEvent<HTMLAnchorElement>) => {
        event.preventDefault();
        const href = event.currentTarget.getAttribute('href');
        if (href?.startsWith('#')) {
            const targetElement = document.querySelector(href);
            if (targetElement) {
                targetElement.scrollIntoView({ behavior: 'smooth' });
            }
        }
    };

    const navLinks = [
        { href: '#practicas', label: 'Áreas' },
        { href: '#beneficios', label: 'Beneficios' },
        { href: '#testimonios', label: 'Testimonios' },
    ];

    return (
        <header className={`sticky top-0 z-40 bg-white/95 backdrop-blur-sm transition-shadow duration-300 ${isScrolled ? 'shadow-md' : ''}`}>
            <div className="container mx-auto px-4 sm:px-6 py-4 flex justify-between items-center">
                <a href="/" className="text-lg sm:text-xl font-bold text-brand-black tracking-tight hover:text-brand-gold transition">
                    Estudio Jurídico <span className="text-brand-gold">LABRA & BALMACEDA</span>
                </a>

                <nav className="hidden md:flex items-center space-x-6 lg:space-x-8 text-sm font-semibold">
                    {navLinks.map(link => (
                        <a key={link.href} href={link.href} className="text-brand-black hover:text-brand-gold transition" onClick={(e) => { handleScrollClick(e); trackNavClick(link.label); }}>
                            {link.label}
                        </a>
                    ))}
                    <a href="#consulta" className="text-white bg-brand-black hover:bg-brand-gold px-5 py-2.5 rounded-lg transition duration-300 shadow-md hover:shadow-lg" onClick={(e) => { handleScrollClick(e); trackCTAClick('Header CTA'); }}>
                        Consulta Gratis
                    </a>
                    <a href="tel:+56977646224" className="text-brand-black hover:text-brand-gold flex items-center gap-2" onClick={trackPhoneClick}>
                        <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                            <path d="M2 3a1 1 0 011-1h2.153a1 1 0 01.986.836l.74 4.435a1 1 0 01-.54 1.06l-1.548.773a11.037 11.037 0 006.105 6.105l.774-1.548a1 1 0 011.059-.54l4.435.74a1 1 0 01.836.986V17a1 1 0 01-1 1h-2C7.82 18 2 12.18 2 5V3z"/>
                        </svg>
                        <span className="hidden lg:inline">+56 9 7764 6224</span>
                    </a>
                </nav>

                <button id="mobile-menu-toggle" onClick={toggleMenu} className="md:hidden text-brand-black focus:outline-none focus:ring-2 focus:ring-brand-gold rounded p-2" aria-label="Abrir menú de navegación" aria-expanded={isMenuOpen}>
                    {isMenuOpen ? (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path>
                        </svg>
                    ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"></path>
                        </svg>
                    )}
                </button>
            </div>

            {isMenuOpen && (
                <nav className="md:hidden bg-white border-t border-gray-200 shadow-lg">
                    <div className="flex flex-col space-y-1 p-4">
                        {navLinks.map(link => (
                            <a key={link.href} href={link.href} className="px-4 py-3 text-brand-black font-semibold hover:bg-gray-50 rounded-lg transition" onClick={(e) => { handleScrollClick(e); trackNavClick(`${link.label} Mobile`); toggleMenu(); }}>
                                {link.label === 'Áreas' ? 'Áreas de Práctica' : link.label}
                            </a>
                        ))}
                        <div className="pt-2 border-t border-gray-200 mt-2">
                            <a href="tel:+56977646224" className="flex items-center gap-2 px-4 py-3 text-brand-black font-semibold hover:bg-gray-50 rounded-lg transition" onClick={trackPhoneClick}>
                                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                                    <path d="M2 3a1 1 0 011-1h2.153a1 1 0 01.986.836l.74 4.435a1 1 0 01-.54 1.06l-1.548.773a11.037 11.037 0 006.105 6.105l.774-1.548a1 1 0 011.059-.54l4.435.74a1 1 0 01.836.986V17a1 1 0 01-1 1h-2C7.82 18 2 12.18 2 5V3z"/>
                                </svg>
                                Llamar: +56 9 7764 6224
                            </a>
                            <a href="#consulta" className="block mt-2 text-center bg-brand-black text-white px-4 py-3 rounded-lg font-bold hover:bg-brand-gold transition" onClick={(e) => { handleScrollClick(e); trackCTAClick('Mobile Menu CTA'); toggleMenu(); }}>
                                Consulta Gratuita
                            </a>
                        </div>
                    </div>
                </nav>
            )}
        </header>
    );
};

export default Header;

