import React, { useState } from 'react';
import { trackFormSubmission, trackFormSubmissionError } from '../services/tracking';

type FormStatus = 'idle' | 'loading' | 'success' | 'error';

// Helper function to encode form data for Netlify
const encode = (data: { [key: string]: any }) => {
    return Object.keys(data)
        .map(key => encodeURIComponent(key) + "=" + encodeURIComponent(data[key]))
        .join("&");
}

const ConsultationForm: React.FC = () => {
    const [formData, setFormData] = useState({
        nombre: '',
        email: '',
        telefono: '',
        comuna: '',
        area: '',
        urgencia: 'Media',
        descripcion: '',
        consentimiento: false,
    });
    const [errors, setErrors] = useState<{ [key: string]: string }>({});
    const [status, setStatus] = useState<FormStatus>('idle');

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const checked = (e.target as HTMLInputElement).checked;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value,
        }));
    };

    const validate = (): boolean => {
        const newErrors: { [key: string]: string } = {};
        if (!formData.nombre) newErrors.nombre = 'El nombre es requerido.';
        if (!formData.email || !/\S+@\S+\.\S+/.test(formData.email)) newErrors.email = 'Email inválido o requerido.';
        if (!formData.telefono) newErrors.telefono = 'Teléfono es requerido.';
        if (!formData.comuna) newErrors.comuna = 'Comuna es requerida.';
        if (!formData.area) newErrors.area = 'Área es requerida.';
        if (!formData.descripcion) newErrors.descripcion = 'La descripción es requerida.';
        if (!formData.consentimiento) newErrors.consentimiento = 'Debe aceptar la política de privacidad.';
        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!validate()) {
            return;
        }

        setStatus('loading');
        try {
            await fetch("/", {
                method: "POST",
                headers: { "Content-Type": "application/x-www-form-urlencoded" },
                body: encode({ "form-name": "consulta", ...formData })
            });

            setStatus('success');
            trackFormSubmission(formData);

        } catch (error) {
            setStatus('error');
            trackFormSubmissionError(error);
        }
    };

    const comunaOptions = ["Puerto Montt", "Puerto Varas", "Frutillar", "Llanquihue", "Puerto Octay", "Purranque", "Osorno", "Calbuco", "Ancud", "Castro", "Otra"];
    const areaOptions = [
        { value: "Derecho de Familia", label: "Derecho de Familia (Divorcio, Alimentos)"},
        { value: "Derecho Civil", label: "Derecho Civil (Herencias, Contratos)"},
        { value: "Derecho Concursal", label: "Derecho Concursal (Deudas, Quiebras)"},
        { value: "Juicios de Arriendo", label: "Juicios de Arriendo (Expulsión)"},
        { value: "Otro", label: "Otro (Especificar en descripción)"},
    ];

    return (
        <section id="consulta" className="py-12 sm:py-16 md:py-24 bg-gradient-to-br from-gray-100 to-white">
            <div className="container mx-auto px-4 sm:px-6 max-w-4xl">
                <div className="bg-white p-6 sm:p-10 md:p-12 rounded-2xl shadow-2xl border-t-8 border-brand-gold">
                    <div className="text-center mb-8">
                        <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold mb-3 text-brand-black">Consulta Legal Gratuita</h2>
                        <p className="text-base sm:text-lg text-neutro-gris mb-4">Respondemos en menos de <strong className="text-brand-gold">24 horas</strong>. Confidencialidad 100% garantizada.</p>
                    </div>

                    {status === 'success' ? (
                        <div className="bg-green-50 border border-green-400 text-green-700 px-4 py-3 rounded-lg relative text-center" role="alert">
                            <strong className="font-bold">✓ ¡Gracias por tu consulta!</strong>
                            <span className="block sm:inline"> Un abogado se contactará contigo en breve.</span>
                        </div>
                    ) : (
                    <form name="consulta" onSubmit={handleSubmit} className="space-y-6" noValidate data-netlify="true" netlify-honeypot="bot-field">
                        <input type="hidden" name="form-name" value="consulta" />
                        <div className="grid sm:grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="nombre" className="block text-sm font-semibold text-gray-700 mb-2">Nombre completo <span className="text-red-500">*</span></label>
                                <input type="text" id="nombre" name="nombre" value={formData.nombre} onChange={handleChange} required placeholder="Juan Pérez" className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 transition"/>
                                {errors.nombre && <p className="text-red-500 text-xs mt-1">{errors.nombre}</p>}
                            </div>
                            <div>
                                <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-2">Email <span className="text-red-500">*</span></label>
                                <input type="email" id="email" name="email" value={formData.email} onChange={handleChange} required placeholder="ejemplo@correo.com" className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 transition"/>
                                {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
                            </div>
                        </div>

                        <div className="grid sm:grid-cols-2 gap-4">
                            <div>
                                <label htmlFor="telefono" className="block text-sm font-semibold text-gray-700 mb-2">Teléfono/WhatsApp <span className="text-red-500">*</span></label>
                                <input type="tel" id="telefono" name="telefono" value={formData.telefono} onChange={handleChange} required placeholder="+56 9 8765 4321" className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 transition"/>
                                {errors.telefono && <p className="text-red-500 text-xs mt-1">{errors.telefono}</p>}
                            </div>
                             <div>
                                <label htmlFor="comuna" className="block text-sm font-semibold text-gray-700 mb-2">Comuna <span className="text-red-500">*</span></label>
                                <select id="comuna" name="comuna" value={formData.comuna} onChange={handleChange} required className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 transition bg-white">
                                    <option value="">Seleccione...</option>
                                    {comunaOptions.map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                                {errors.comuna && <p className="text-red-500 text-xs mt-1">{errors.comuna}</p>}
                            </div>
                        </div>

                        <div>
                            <label htmlFor="descripcion" className="block text-sm font-semibold text-gray-700 mb-2">Descripción breve del caso <span className="text-red-500">*</span></label>
                            <textarea id="descripcion" name="descripcion" value={formData.descripcion} onChange={handleChange} required rows={5} placeholder="Por favor, describe tu situación..." className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-brand-gold focus:ring-2 focus:ring-brand-gold/20 transition resize-y"></textarea>
                            {errors.descripcion && <p className="text-red-500 text-xs mt-1">{errors.descripcion}</p>}
                        </div>

                        <div className="flex items-start gap-3">
                            <input type="checkbox" id="consentimiento" name="consentimiento" checked={formData.consentimiento} onChange={handleChange} required className="mt-1 w-4 h-4 text-brand-black border-gray-300 rounded focus:ring-brand-gold"/>
                            <label htmlFor="consentimiento" className="text-xs sm:text-sm text-gray-600">
                                Acepto la Política de Privacidad y autorizo el contacto legal. <span className="text-red-500">*</span>
                                {errors.consentimiento && <span className="block text-red-500">{errors.consentimiento}</span>}
                            </label>
                        </div>

                        {status === 'error' && (
                          <div className="bg-red-50 border border-red-400 text-red-700 px-4 py-3 rounded-lg relative" role="alert">
                            <strong className="font-bold">✗ Error al enviar. </strong>
                            <span className="block sm:inline">Intenta por WhatsApp.</span>
                          </div>
                        )}

                        <button type="submit" disabled={status === 'loading'} className="w-full px-6 py-4 text-lg sm:text-xl font-bold uppercase rounded-xl bg-brand-black text-white hover:bg-brand-gold transition duration-300 shadow-xl hover:shadow-2xl transform hover:scale-[1.02] disabled:opacity-50 disabled:cursor-not-allowed">
                          {status === 'loading' ? 'Enviando...' : '📨 Solicitar Consulta Gratuita'}
                        </button>
                    </form>
                    )}
                </div>
            </div>
        </section>
    );
};

export default ConsultationForm;

import React, { useState, useEffect } from 'react';
import { trackEvent } from '../services/tracking';

const CookieBanner: React.FC = () => {
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const consent = localStorage.getItem('cookieConsent');
        if (!consent) {
            const timer = setTimeout(() => {
                setIsVisible(true);
            }, 2000);
            return () => clearTimeout(timer);
        }
    }, []);

    const handleAccept = () => {
        localStorage.setItem('cookieConsent', 'accepted');
        setIsVisible(false);
        trackEvent('Cookie Consent', 'Accepted');
    };

    const handleReject = () => {
        localStorage.setItem('cookieConsent', 'rejected');
        setIsVisible(false);
        trackEvent('Cookie Consent', 'Rejected');
    };

    if (!isVisible) {
        return null;
    }

    return (
        <div className="fixed bottom-0 left-0 right-0 bg-brand-black text-white p-4 shadow-2xl z-50 border-t border-brand-gold/30">
            <div className="container mx-auto flex flex-col sm:flex-row items-center justify-between gap-4">
                <p className="text-xs sm:text-sm text-center sm:text-left text-gray-300">
                    🍪 Utilizamos cookies para mejorar tu experiencia. Al navegar, aceptas nuestra 
                    <a href="#" className="underline hover:text-brand-gold transition ml-1">Política de Cookies</a>.
                </p>
                <div className="flex gap-3">
                    <button onClick={handleAccept} className="px-6 py-2 bg-brand-gold hover:bg-yellow-700 rounded-lg font-bold text-sm transition">
                        Aceptar
                    </button>
                    <button onClick={handleReject} className="px-6 py-2 bg-gray-700 hover:bg-gray-800 rounded-lg font-bold text-sm transition">
                        Rechazar
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CookieBanner;

