        marketing: false,
        analytics: false
    });

    useEffect(() => {
        const consent = localStorage.getItem('cookie_consent_v2');
        if (!consent) {
            const timer = setTimeout(() => setIsVisible(true), 1500);
            return () => clearTimeout(timer);
        } else {
            // Aplicar consentimiento guardado si ya existe
            const saved = JSON.parse(consent);
            applyConsent(saved);
        }
    }, []);

    const applyConsent = (consent: ConsentSettings) => {
        // Fix: Cast window to any to access the 'gtag' property which is injected globally by Google Tag Manager
        const anyWindow = window as any;
        if (typeof anyWindow.gtag === 'function') {
            anyWindow.gtag('consent', 'update', {
                'ad_storage': consent.marketing ? 'granted' : 'denied',
                'ad_user_data': consent.marketing ? 'granted' : 'denied',
                'ad_personalization': consent.marketing ? 'granted' : 'denied',
                'analytics_storage': consent.analytics ? 'granted' : 'denied'
            });
